visualizerParams.ghostCode:
#include <stdio.h>
#include <math.h>

int main() {
    long long n = 1101;
    int decimal = 0, i = 0, rem;
    while (n != 0) {
        rem = n % 10;
        n /= 10;
        decimal += rem * pow(2, i);
        ++i;
    }
    printf("Decimal: %d\n", decimal);
    return 0;
}

